    source_url: "https://www.sodnapraksa.si/search.php?q=&advanceSerch=1&database[IESP]=IESP&trib_title[Višje sodišče v Mariboru]=\"Višje sodišče v Mariboru\"&trib_title[Višje sodišče v Ljubljani]=\"Višje sodišče v Ljubljani\"&trib_title[Višje sodišče v Kopru]=\"Višje sodišče v Kopru\"&trib_title[Višje sodišče v Celju]=\"Višje sodišče v Celju\"&dep_title[Civilni oddelek]=\"Civilni oddelek\"&dep_title[Gospodarski oddelek]=\"Gospodarski oddelek\"&dep_title[Izvršilni oddelek]=\"Izvršilni oddelek\"&dep_title[Kazenski oddelek]=\"Kazenski oddelek\"&dep_title[Oddelek za prekrške]=\"Oddelek za prekrške\"&meet_dateFrom=14.03.2024&meet_dateTo=29.05.2026&order=date&direction=desc&_submit=išči&rowsPerPage=20&page=151&id=2015081111483160",
